import pandas as pd
import numpy as np

def task_func(d):
    try:
        if not isinstance(d, list):
            raise ValueError("Input is not a list of dictionaries.")

        df = pd.DataFrame(d)
        keys = ['x', 'y', 'z']

        # Check if all dictionaries in the list have the same keys
        if len(set(df.columns)) != len(keys):
            raise ValueError("All dictionaries in the list should have the same keys.")

        stats_dict = {key: {} for key in keys}

        for key in keys:
            data = df[key].tolist()
            if not all(isinstance(val, (int, float)) for val in data):
                raise ValueError("All values in the dictionaries should be numeric.")

            stats_dict[key]['mean'] = np.mean(data)
            stats_dict[key]['sum'] = np.sum(data)
            stats_dict[key]['max'] = max(data)
            stats_dict[key]['min'] = min(data)
            stats_dict[key]['std'] = np.std(data)

        return stats_dict, None
    except Exception as e:
        return None, ValueError(e)
